+	if formatStr != "" {
+		format, err := robot.ParseRobotFormat(formatStr)
+		if err != nil {
+			fmt.Fprintf(os.Stderr, "Warning: %v, using default (auto)\n", err)
+			robot.OutputFormat = robot.FormatAuto
+			return
+		}
+		robot.OutputFormat = format
+	} else {
+		robot.OutputFormat = robot.FormatAuto
+	}
+}
