+		{"id": 2, "tags": []string{"c"}},
+	}
+
+	output, err := toonEncode(input, "\t")
+	if err != nil {
+		t.Fatalf("error: %v", err)
+	}
+
+	// Should contain quoted JSON for the tags field
+	if !strings.Contains(output, `["a","b"]`) && !strings.Contains(output, `"[\"a\",\"b\"]"`) {
